namespace sv_f7184242e3e2433280915611137b6d6d.Services;

/// <summary>
/// Server-side IShipmentService that simulates a slow backend with seeded fake data.
/// </summary>
public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment(
            TrackingNumber: "PKG-001",
            Status: "In Transit",
            Location: "Memphis, TN",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Package picked up", new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Arrived at sorting facility", new DateTimeOffset(2026, 5, 21, 3, 30, 0, TimeSpan.Zero)),
                new StatusUpdate("In transit to destination", new DateTimeOffset(2026, 5, 22, 8, 15, 0, TimeSpan.Zero)),
            ]),
        ["PKG-002"] = new Shipment(
            TrackingNumber: "PKG-002",
            Status: "Delivered",
            Location: "Seattle, WA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Package picked up", new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Arrived at regional hub", new DateTimeOffset(2026, 5, 19, 14, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Out for delivery", new DateTimeOffset(2026, 5, 21, 7, 45, 0, TimeSpan.Zero)),
                new StatusUpdate("Delivered", new DateTimeOffset(2026, 5, 21, 11, 22, 0, TimeSpan.Zero)),
            ]),
        ["PKG-003"] = new Shipment(
            TrackingNumber: "PKG-003",
            Status: "Processing",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Label created", new DateTimeOffset(2026, 5, 22, 14, 0, 0, TimeSpan.Zero)),
            ]),
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_f7184242e3e2433280915611137b6d6d.Client.Services
@rendermode InteractiveAuto
@implements IDisposable
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p><em>Loading shipment details for @TrackingNumber&hellip;</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning" role="alert">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Status History</h3>
    <ul>
        @foreach (var update in _shipment.StatusUpdates)
        {
            <li>@update.Timestamp.ToString("g") &mdash; @update.Description</li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;
    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation away or disposal — silently abandon.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

